
-- Creación de la base de datos (si no existe)
CREATE DATABASE IF NOT EXISTS universidad_dw;
USE universidad_dw;

-- Tabla de Dimensión: Dim_Estudiante
CREATE TABLE IF NOT EXISTS Dim_Estudiante (
    sk_estudiante INT AUTO_INCREMENT PRIMARY KEY,
    id_estudiante INT NOT NULL,
    nombre_estudiante VARCHAR(255) NOT NULL,
    ciudad VARCHAR(255) NOT NULL,
    UNIQUE (id_estudiante)
);

-- Tabla de Dimensión: Dim_Curso
CREATE TABLE IF NOT EXISTS Dim_Curso (
    sk_curso INT AUTO_INCREMENT PRIMARY KEY,
    nombre_curso VARCHAR(255) NOT NULL,
    UNIQUE (nombre_curso)
);

-- Tabla de Dimensión: Dim_Profesor
CREATE TABLE IF NOT EXISTS Dim_Profesor (
    sk_profesor INT AUTO_INCREMENT PRIMARY KEY,
    nombre_profesor VARCHAR(255) NOT NULL,
    UNIQUE (nombre_profesor)
);

-- Tabla de Dimensión: Dim_Tiempo
CREATE TABLE IF NOT EXISTS Dim_Tiempo (
    sk_tiempo INT AUTO_INCREMENT PRIMARY KEY,
    fecha_completa DATE NOT NULL,
    anio INT NOT NULL,
    mes INT NOT NULL,
    dia INT NOT NULL,
    UNIQUE (fecha_completa)
);

-- Tabla de Hechos: Fact_Matriculas
CREATE TABLE IF NOT EXISTS Fact_Matriculas (
    id_matricula INT PRIMARY KEY, -- Mantener la clave natural para trazabilidad
    sk_estudiante INT NOT NULL,
    sk_curso INT NOT NULL,
    sk_profesor INT NOT NULL,
    sk_tiempo INT NOT NULL,
    nota DECIMAL(3, 2) NOT NULL,
    cantidad INT DEFAULT 1,
    FOREIGN KEY (sk_estudiante) REFERENCES Dim_Estudiante(sk_estudiante),
    FOREIGN KEY (sk_curso) REFERENCES Dim_Curso(sk_curso),
    FOREIGN KEY (sk_profesor) REFERENCES Dim_Profesor(sk_profesor),
    FOREIGN KEY (sk_tiempo) REFERENCES Dim_Tiempo(sk_tiempo)
);


