-- 4. Consultas de Análisis Inicial

-- Consulta 1: Promedio de notas por curso
SELECT dc.nombre_curso, AVG(fm.nota) AS promedio_nota
FROM Fact_Matriculas fm
JOIN Dim_Curso dc ON fm.sk_curso = dc.sk_curso
GROUP BY dc.nombre_curso
ORDER BY promedio_nota DESC;

-- Consulta 2: Número de matrículas por ciudad
SELECT de.ciudad, COUNT(fm.id_matricula) AS total_matriculas
FROM Fact_Matriculas fm
JOIN Dim_Estudiante de ON fm.sk_estudiante = de.sk_estudiante
GROUP BY de.ciudad
ORDER BY total_matriculas DESC;

-- Consulta 3: Promedio de notas por profesor
SELECT dp.nombre_profesor, AVG(fm.nota) AS promedio_nota
FROM Fact_Matriculas fm
JOIN Dim_Profesor dp ON fm.sk_profesor = dp.sk_profesor
GROUP BY dp.nombre_profesor
ORDER BY promedio_nota DESC;

-- Consulta 4: Matrículas a lo largo del tiempo (por año y mes)
SELECT dt.anio, dt.mes, COUNT(fm.id_matricula) AS total_matriculas
FROM Fact_Matriculas fm
JOIN Dim_Tiempo dt ON fm.sk_tiempo = dt.sk_tiempo
GROUP BY dt.anio, dt.mes
ORDER BY dt.anio, dt.mes;

-- Consulta 5: Top 5 estudiantes con mejor promedio de notas (considerando al menos 2 matrículas)
SELECT de.nombre_estudiante, AVG(fm.nota) AS promedio_general
FROM Fact_Matriculas fm
JOIN Dim_Estudiante de ON fm.sk_estudiante = de.sk_estudiante
GROUP BY de.nombre_estudiante
HAVING COUNT(fm.id_matricula) >= 2
ORDER BY promedio_general DESC
LIMIT 5;
